def safe_api_call(url: str, method: str, allowlist: list[str], responses: dict[str, str]) -> str:
    # Only GET method is allowed
    if method != 'GET':
        raise ValueError("Only GET method is allowed")

    # Must be HTTPS
    if not url.startswith('https://'):
        raise ValueError("Only HTTPS URLs are allowed")

    # Extract host from URL
    # Remove https:// prefix
    url_without_scheme = url[8:]  # Remove 'https://'

    # Find the host part (everything before first '/' or end of string)
    slash_index = url_without_scheme.find('/')
    if slash_index == -1:
        host = url_without_scheme
    else:
        host = url_without_scheme[:slash_index]

    # Remove port if present
    colon_index = host.find(':')
    if colon_index != -1:
        host = host[:colon_index]

    # Check if host is in allowlist
    if host not in allowlist:
        raise ValueError("Host not in allowlist")

    # Check for localhost
    if host == 'localhost' or host == '127.0.0.1' or host == '::1':
        raise ValueError("Localhost access not allowed")

    # Check if host is a bare IP address
    if _is_ip_address(host):
        raise ValueError("Bare IP addresses not allowed")

    # Check for private IP ranges (if it somehow got through the IP check)
    if _is_private_ip(host):
        raise ValueError("Private IP addresses not allowed")

    # Look up response
    response_key = f"{method} {url}"
    if response_key not in responses:
        raise ValueError("No response found for request")

    return responses[response_key]

def _is_ip_address(host: str) -> bool:
    # Check IPv4
    parts = host.split('.')
    if len(parts) == 4:
        try:
            for part in parts:
                num = int(part)
                if num < 0 or num > 255:
                    return False
            return True
        except ValueError:
            pass

    # Check IPv6 (basic check for colons)
    if ':' in host:
        return True

    return False

def _is_private_ip(host: str) -> bool:
    # This is a basic check - since we're rejecting all IPs anyway,
    # this is mainly for completeness
    parts = host.split('.')
    if len(parts) == 4:
        try:
            first = int(parts[0])
            second = int(parts[1])

            # 10.0.0.0/8
            if first == 10:
